    if k % d == 0:
        print('not prime')
        break
else:
    print('prime')

solution:
n = int(input())
for k in range(2, n + 1):
    is_prime = True
    for d in range(2, int(k**0.5) + 1):
        if k % d == 0:
            is_prime = False
            break
    if is_prime:
        print(k)
